// 1️⃣ Pega o texto de entrada
let response = $json?.output || $json?.text || $json?.body || $json?.response || "";
response = (response || "").toString().trim();

// 2️⃣ Regex atualizado
const mdImageRegex = /!\[[^\]]*\]\((https?:\/\/[^\)]+?\.(?:jpg|jpeg|png|webp|gif)[^\)]*)\)/i;
const urlRegex = /(https?:\/\/[^\s]+?\.(?:jpg|jpeg|png|webp|gif)(?:\?[^\s]*)?)/i;

// 3️⃣ Busca imagem e legenda
let match = response.match(mdImageRegex) || response.match(urlRegex);
let imageUrl = match ? match[1] || match[0] : null;

// 🔹 Limpa URL de parênteses ou espaços extras no final
if (imageUrl) {
  imageUrl = imageUrl.trim().replace(/\)+$/, '');
}

let caption = response.replace(mdImageRegex, "").replace(urlRegex, "").trim();
if (imageUrl && !caption) caption = "Imagem do produto";

// 4️⃣ Função para baixar e converter para Base64
async function downloadImageAsBase64(url) {
  try {
    const res = await fetch(url);
    if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`);
    const arrayBuffer = await res.arrayBuffer();
    const base64 = Buffer.from(arrayBuffer).toString('base64');
    // Define sempre como PNG
    return { base64: `data:image/png;base64,${base64}`, mimeType: 'image/png' };
  } catch (err) {
    console.error('Erro ao baixar imagem:', err.message);
    return null;
  }
}

// 5️⃣ Baixa a imagem se existir
let binaryData = null;
if (imageUrl) {
  const result = await downloadImageAsBase64(imageUrl);
  if (result) {
    binaryData = {
      data: result.base64,
      mimeType: 'image/png',
      fileName: 'imagem.png'
    };
  }
}

// 6️⃣ Retorna item compatível com n8n
return [
  {
    json: {
      caption,
      imageUrl,
      hasImage: !!binaryData
    },
    binary: binaryData ? { imagem: binaryData } : undefined
  }
];

// Pega o texto do campo "output"
const texto = items[0].json.output;

// Divide o texto pelos parágrafos (duas quebras de linha)
const paragrafos = texto.split(/\n\s*\n/);

// Retorna o array de parágrafos
return [
  {
    json: {
      paragrafos,
    },
  },
];
